-- Enrichment marathon batch: WooRank, WordHero, WordPress, WordPress.com, Wordtune, Workable, Workato, Workday

-- ── WooRank ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$WooRank is a website review and SEO audit platform that scores site health, tracks keyword rankings, and generates white-label reports for agencies and marketers.$q$, short_description),
  pricing_model = COALESCE($q$subscription$q$, pricing_model),
  starting_price = COALESCE($q$$79.99/month (Pro plan, billed monthly)$q$, starting_price),
  founded_year = COALESCE(2010, founded_year),
  company_size = COALESCE($q$11-50 employees$q$, company_size),
  headquarters = COALESCE($q$Brussels, Belgium$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$WooRank Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$See what WooRank does, how its site audit and keyword tracking tools work, and what the Pro, Premium and Enterprise plans cost before you sign up.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$WooRank is a website review and SEO audit tool founded in 2010 and headquartered in Brussels, Belgium. It is built for small business owners, digital marketing agencies, and SEO consultants who need a fast, single-page snapshot of a website's technical health alongside deeper ongoing tracking tools. The product's signature feature is its instant Website Review, which crawls a URL and returns an overall SEO score along with graded checks across on-page SEO, mobile usability, technology stack, backlinks, social presence, and local SEO signals. Beyond the one-time review, WooRank offers a Site Crawl tool that performs a deep technical audit across an entire domain to surface issues like broken links, missing alt text, duplicate content, slow page speed, and crawlability problems. Its Keyword Tool lets users research target keywords, track ranking positions over time, and localize tracking to specific countries, regions, or cities, comparing performance against named competitors. WooRank also includes backlink monitoring and competitive analysis features that show how a domain stacks up against rivals on visibility metrics. Because many WooRank customers are agencies, the platform supports white-label PDF reporting so consultants can rebrand audit findings and keyword data for client delivery, plus a Chrome extension for on-the-fly reviews while browsing. WooRank is sold on a subscription basis with three tiers: a Pro plan at 79.99 dollars per month, a Premium plan at 199.99 dollars per month with higher usage limits and more keyword tracking capacity, and a custom-quoted Enterprise plan for larger agencies and in-house teams needing higher volume, more seats, or dedicated support. All paid plans are available with a 14-day free trial, and pricing scales primarily with the number of tracked keywords, competitor domains, and reviewed sites rather than by user seat. WooRank differentiates itself from heavier enterprise SEO suites like Semrush or Ahrefs by focusing on quick, digestible scorecards and review-style outputs that are easy to hand to non-technical stakeholders, rather than deep backlink index exploration or content research at scale. It integrates with Google Analytics and Google Search Console to pull in real traffic and search performance data alongside its own crawl-based findings, giving users a combined view of technical health and actual search visibility in one dashboard.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '72ffb4a5-e2e0-4903-8155-e17e23b71215';

