-- ── WordHero ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$WordHero is an AI writing tool that generates blog posts, marketing copy, and images from templates, aiming to speed up content creation while adapting to a user's writing style.$q$, short_description),
  pricing_model = COALESCE($q$subscription$q$, pricing_model),
  starting_price = COALESCE($q$$29/month (Creator plan, billed annually)$q$, starting_price),
  founded_year = COALESCE(2021, founded_year),
  company_size = COALESCE($q$1-10 employees$q$, company_size),
  headquarters = COALESCE($q$Singapore$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$WordHero Review 2026: AI Writing Tool Features and Pricing$q$, seo_title),
  seo_meta_description = COALESCE($q$Learn what WordHero does, how its AI blog and content templates work, and compare Creator versus Infinity plan pricing before you subscribe.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$WordHero is an AI-powered writing tool launched in July 2021 by Jeff Tay, operated through J1 Holdings Pte Ltd, a Singapore-based technology company incorporated in 2014 and headquartered in the Guoco Tower area of Singapore. The product is aimed at bloggers, content marketers, small business owners, and digital publishers who want to speed up first-draft content creation using large language models rather than write every piece from scratch. Its central feature is one-click, long-form blog post generation, where a user provides a topic or outline and WordHero produces a structured draft that can then be edited in its built-in long-form editor. The editor includes a keyword assistant to help writers work target search terms into the draft for SEO purposes, plus a library of pre-built templates covering formats such as product descriptions, ad copy, social captions, and outlines, so users are not limited to full blog posts. WordHero also includes an AI chat feature with a wizard mode intended for brainstorming topics, outlines, and angles before drafting begins, and a companion feature called WordHero Art for generating AI images to accompany written content. The platform advertises support for content generation in 108 languages, extending its use beyond English-language publishing. WordHero markets itself on being able to adapt output to an individual user's established writing voice and style rather than producing generic AI-sounding text, though as with all AI writing tools, output quality and voice-matching accuracy vary by use case and generally benefit from human editing before publishing. Pricing is subscription-based with two tiers. The Creator plan costs 29 dollars per month when billed annually (49 dollars per month if paying monthly) and includes unlimited content generation along with 160,000 Enhanced Mode tokens for higher-quality outputs. The Infinity plan, aimed at small teams of up to five members, costs 79 dollars per month billed annually (99 dollars per month if paying monthly) and includes unlimited Enhanced Mode access rather than a token cap. Both plans come with a 14-day money-back guarantee, and the company has reported over 30,000 active users. WordHero competes in a crowded AI writing assistant category alongside tools like Writesonic and Jasper, differentiating primarily on its blog-focused one-click workflow and its lower entry price point relative to some enterprise-oriented competitors.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '6741ec68-b40f-4b14-9d8b-2af8c98c0e2f';

