-- ── WordPress ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$WordPress is a free, open-source content management system that powers the majority of self-hosted websites on the internet, extensible with thousands of themes and plugins.$q$, short_description),
  pricing_model = COALESCE($q$open-source$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2003, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE($q$Community project (WordPress Foundation, San Francisco, California)$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$WordPress (WordPress.org) Explained: Free Open-Source CMS Guide$q$, seo_title),
  seo_meta_description = COALESCE($q$Understand what WordPress.org software is, how the free open-source CMS works, and how it differs from the hosted WordPress.com service.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$WordPress, distributed through WordPress.org, is a free and open-source content management system originally released on May 27, 2003, as version 0.7, created by American developer Matt Mullenweg and British developer Mike Little as a fork of the earlier b2/cafelog blogging platform. The software is licensed under the GNU General Public License version 2 or later (GPLv2+), meaning anyone can freely use, study, modify, and redistribute it, including for commercial purposes, and there is no vendor lock-in since the software can be self-hosted on any server that meets its requirements. WordPress.org is distinct from WordPress.com, the commercial hosted service operated by Automattic. WordPress.org is simply the home of the open-source software project itself, distributing the core CMS software, a directory of free themes and plugins, support forums, and documentation, but it does not sell hosting or host websites directly. To run a WordPress.org site, a user or organization must obtain their own hosting from a third-party provider (such as WP Engine, Bluehost, or SiteGround) and install the software themselves, giving them full control over configuration, custom code, and server-level settings. As of the mid-2020s, WordPress powers a majority of all websites on the internet that use a known content management system, a dominance built on its plugin and theme ecosystem, which numbers in the tens of thousands of free and premium extensions covering everything from ecommerce (via WooCommerce) to SEO (via Yoast or Rank Math) to page building (via Elementor or the native block-based Gutenberg editor). Development of WordPress core is coordinated by a community of volunteer and sponsored contributors, with Automattic being the largest corporate sponsor of contributor time, and governance historically centered on Matt Mullenweg as the project's co-creator and lead. Because it is free and self-hosted, WordPress has no subscription tiers, no seat limits, and no company revenue model tied to the software itself; costs to site owners come instead from hosting, premium themes and plugins, developer time, and optional maintenance services. WordPress is widely used across blogs, small business websites, media publications, ecommerce stores, and enterprise sites, and it remains a foundational reference point in comparisons with proprietary website builders like Wix, Squarespace, and Webflow, as well as with the hosted WordPress.com service that runs the same underlying software as a managed product.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '8741e733-7b13-489c-8696-9d50fbf35b42';

