-- ── WordPress.com ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$WordPress.com is a managed hosting platform run by Automattic that packages the WordPress software into a paid website and blogging service, with a limited free plan and paid tiers for domains, plugins, and ecommerce.$q$, short_description),
  pricing_model = COALESCE($q$freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free (paid plans from $4/month billed annually)$q$, starting_price),
  founded_year = COALESCE(2005, founded_year),
  company_size = COALESCE($q$1,000-5,000 employees (Automattic, fully distributed)$q$, company_size),
  headquarters = COALESCE($q$San Francisco, California, United States (Automattic, fully distributed company)$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$WordPress.com Pricing and Features Guide (2026)$q$, seo_title),
  seo_meta_description = COALESCE($q$Compare WordPress.com's free plan and paid Personal, Premium, Business, and Commerce tiers, and see how the hosted platform differs from self-hosted WordPress.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$WordPress.com is a managed, hosted website and blogging platform operated by Automattic, the company co-founded in 2005 by WordPress creator Matt Mullenweg. Where WordPress.org distributes free, self-hosted open-source software that users must install on their own server, WordPress.com is a commercial product that runs that same underlying WordPress software as a fully managed service, handling hosting, security, backups, and core updates on the customer's behalf in exchange for a subscription fee. Automattic is a fully distributed company with no central headquarters requirement for staff, though it maintains a registered San Francisco, California base, and employs a large global workforce across its portfolio of products, which also includes WooCommerce, Jetpack, Tumblr, and Simplenote. WordPress.com offers a genuinely free tier with no credit card required, though the free plan carries meaningful limitations: no custom domain, WordPress.com branding and ads may appear on the site, no plugin installation, no premium themes, and no monetization tools. Paid plans unlock progressively more capability. As of mid-2026, the Personal plan is priced around 4 dollars per month billed annually (9 dollars per month if paying monthly) and adds a free custom domain for the first year and ad removal. The Premium plan is around 8 dollars per month annually (18 dollars monthly) and adds premium themes and more storage. The Business plan, priced around 25 dollars per month annually (40 dollars monthly), is the first tier to unlock full plugin installation and custom theme uploads, along with 200GB of storage, making it the closest equivalent to a typical self-hosted WordPress setup. The Commerce plan, around 45 dollars per month annually (70 dollars monthly), builds on Business with integrated ecommerce tools for selling products and services directly through the site. Enterprise-level pricing is available through custom negotiation for large organizations, often through Automattic's WP VIP or Automattic for Agencies programs. WordPress.com bundles hosting, a domain (free for the first year on paid plans), privacy protection, and security into a single subscription price, positioning it as a more turnkey alternative to assembling separate hosting, WordPress installation, and plugin subscriptions manually. It competes directly with other hosted website builders like Wix, Squarespace, and Weebly, while also serving as an on-ramp for users who may later migrate to fully self-hosted WordPress.org for more control.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '6b5c71e6-e1cf-4f55-9339-d6d644c3f1a6';

