-- ── Wordtune ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Wordtune is an AI writing assistant from AI21 Labs that rewrites and paraphrases sentences, adjusts tone, summarizes text, and fixes grammar directly in your browser or documents.$q$, short_description),
  pricing_model = COALESCE($q$freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free (paid plans from $13.99/month)$q$, starting_price),
  founded_year = COALESCE(2017, founded_year),
  company_size = COALESCE($q$51-200 employees (AI21 Labs)$q$, company_size),
  headquarters = COALESCE($q$Tel Aviv, Israel$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Wordtune Review 2026: AI Rewriting Tool Features and Pricing$q$, seo_title),
  seo_meta_description = COALESCE($q$See how Wordtune's AI rewriting, tone, and summarizing tools work, who built it, and how the Free, Advanced, Unlimited, and Teams plans are priced.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Wordtune is an AI-powered writing assistant developed by AI21 Labs, an Israeli AI company founded in November 2017 by Yoav Shoham, Ori Goshen, and Amnon Shashua and headquartered in Tel Aviv. Wordtune was AI21 Labs' first consumer product, launched publicly on October 27, 2020, as a deep-learning writing tool that goes beyond basic grammar checking by understanding sentence context and meaning to suggest full rewrites and paraphrases rather than just flagging errors. Unlike tools built primarily around rule-based grammar correction, Wordtune uses natural language generation models to offer alternative phrasings, adjust tone from casual to formal, shorten or expand sentences, and generate short pieces of contextual content the company calls Spices, such as examples, statistics, counterarguments, or explanations that a writer can insert into their draft. Wordtune is available as a browser extension that works inside Gmail, Google Docs, LinkedIn, Twitter, and most web-based text fields, as well as standalone web and desktop apps, and it includes a reading companion feature called Wordtune Read that can summarize long articles or documents into key points. The product also includes unlimited text correction for grammar and spelling as part of even its free tier. Wordtune's pricing follows a freemium model. The Free plan includes 10 rewrites and Spices per day, 3 monthly summaries, and unlimited grammar and spelling corrections. The Advanced plan is priced at 13.99 dollars per month and raises the daily limit to 30 rewrites and Spices along with 15 monthly summaries. The Unlimited plan is priced at 19.99 dollars per month and removes daily caps entirely, offering unlimited rewrites, Spices, summaries, and premium support. A Teams plan is available at 7.99 dollars per seat per month when billed annually, bundling Unlimited plan features with centralized billing and business-oriented support for organizations equipping multiple writers. Wordtune competes with other AI writing and paraphrasing tools such as Grammarly's rewrite features and QuillBot, but differentiates itself through its focus on contextual, meaning-aware rewriting powered by AI21 Labs' own large language model research, rather than templated content generation. AI21 Labs went on to develop the Jurassic and Jamba families of large language models for enterprise use, with Wordtune remaining its most widely known consumer-facing product.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'a5fa585a-6104-495a-a452-912fb307c35f';

