-- ── Workable ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Workable is an applicant tracking system and HR platform that helps small and mid-sized businesses source candidates, manage hiring pipelines, and handle onboarding and HR tasks.$q$, short_description),
  pricing_model = COALESCE($q$subscription$q$, pricing_model),
  starting_price = COALESCE($q$$299/month (Standard plan, billed annually)$q$, starting_price),
  founded_year = COALESCE(2012, founded_year),
  company_size = COALESCE($q$400-500 employees$q$, company_size),
  headquarters = COALESCE($q$Boston, Massachusetts, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Workable Review 2026: ATS and HR Software Pricing and Features$q$, seo_title),
  seo_meta_description = COALESCE($q$See how Workable's recruiting and HR tools work, compare Standard, Premier, and Enterprise pricing, and learn who the applicant tracking system is built for.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Workable is an applicant tracking system and HR software platform founded in June 2012 in Athens, Greece by Nikos Moraitakis and Spyros Magiatis, originally built to give small and mid-sized businesses recruiting tools comparable to what large enterprises had access to. The company has since grown into a global operation with its primary headquarters in Boston, Massachusetts, and additional offices in Athens, London, and Singapore. Workable's core product is an applicant tracking system that helps companies post jobs to multiple job boards simultaneously, build a branded careers page, source candidates from a searchable people database, screen resumes, schedule interviews, and collaborate with hiring team members through structured evaluation scorecards. In recent product cycles Workable has expanded into an AI-driven recruiter agent that can auto-source and pre-screen candidates, alongside optional add-ons for video interviewing, candidate assessments, SMS texting, and employee referrals. Beyond recruiting, Workable has broadened into a lighter HR information system covering employee onboarding, time-off management, time tracking, e-signatures for offer letters and HR documents, and payroll preparation with third-party payroll integrations, making it a combined hire-to-onboard platform rather than a pure ATS. Workable sells three subscription tiers, all scaled for companies from roughly 1 to 20 employees up through enterprises of 1,000-plus, meaning pricing is based on plan tier and add-ons rather than seat count alone. The Standard plan costs 299 dollars per month billed monthly (3,588 dollars per year, a 20 percent savings if paid annually) and includes core ATS and HRIS functionality, with video interviews, assessments, and SMS texting available as paid add-ons. The Premier plan costs 599 dollars per month (7,188 dollars annually) and bundles in texting, video interviews, assessments, and referrals along with performance and engagement tools that are optional add-ons on Standard. The Enterprise plan costs 719 dollars per month (8,628 dollars annually) and carries the same feature set as Premier but is aimed at larger organizations needing single sign-on and priority support. All plans include a pool of free AI credits for Workable's AI recruiting agent, with additional credits purchasable in bulk packages ranging from roughly 0.095 to 0.12 dollars per credit depending on volume. Workable competes with other SMB and mid-market recruiting platforms such as Greenhouse, Lever, and BambooHR, differentiating through its combination of AI-assisted sourcing, an integrated lightweight HRIS, and pricing structured around flat monthly plan tiers rather than strict per-seat billing.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '63552ca4-8785-47c6-9aaf-f0643adf97b5';

