-- ── Workday ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Workday is a cloud-based enterprise platform for human capital management, financial management, and planning, sold to large and mid-sized organizations on a per-user subscription basis.$q$, short_description),
  pricing_model = COALESCE($q$subscription$q$, pricing_model),
  starting_price = COALESCE($q$Custom quote (HCM estimated from roughly $100/user/year)$q$, starting_price),
  founded_year = COALESCE(2005, founded_year),
  company_size = COALESCE($q$21,000+ employees$q$, company_size),
  headquarters = COALESCE($q$Pleasanton, California, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Workday Review 2026: HCM, Finance, and ERP Platform Explained$q$, seo_title),
  seo_meta_description = COALESCE($q$Understand what Workday's HCM and financial management platform does, who it is built for, and how its subscription pricing is structured.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Workday is a cloud-based enterprise software company founded in March 2005 by David Duffield, the former CEO of PeopleSoft, and Aneel Bhusri, PeopleSoft's former chief strategist, after Oracle's hostile acquisition of PeopleSoft. The company launched its first product in November 2006 and is headquartered in Pleasanton, California, having moved there from Walnut Creek, California in December 2008. Workday's flagship offerings are Human Capital Management (HCM) and Financial Management, sold together or separately as cloud applications for large and mid-sized enterprises, alongside adjacent products such as Workday Adaptive Planning for financial and workforce planning, Workday Payroll, Workday Strategic Sourcing for procurement, Workday Prism Analytics for data analytics, and more recently Workday Illuminate, the company's suite of embedded AI and agent capabilities across its applications. Unlike older on-premises ERP systems, Workday runs entirely as a multi-tenant cloud service with a unified data model and a single, frequently updated codebase across all customers, an architecture the company has marketed as an alternative to legacy systems like SAP and Oracle's on-premises suites. As of fiscal year 2026, Workday employs approximately 21,000 people globally and reported roughly 9.55 billion dollars in annual revenue, an increase of about 13 percent year over year, with the large majority of revenue coming from subscription services rather than professional services. Workday's business model is entirely subscription-based rather than perpetual licensing, consistent with its cloud-native architecture; the company does not publish self-serve pricing, since contracts are individually negotiated based on the specific modules licensed, number of employees or users covered, and implementation scope. Third-party estimates place core HCM subscription costs starting in the range of roughly 100 dollars per user per year, with total contract value increasing substantially once financial management, planning, payroll, and analytics add-ons are included, and implementation costs for large enterprises can run into the millions of dollars when factoring in systems integrator involvement. Workday primarily serves large enterprises and increasingly mid-market organizations across industries including healthcare, higher education, financial services, technology, and government, competing most directly with SAP SuccessFactors, Oracle Cloud HCM, and, in specific modules, with vendors like ADP and NetSuite. The company is publicly traded on the Nasdaq under the ticker WDAY and has become one of the largest independent providers of cloud HCM and financial management software.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '8b71f7fc-c26a-419f-a1fe-0de98471da7f';

