INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('72ffb4a5-e2e0-4903-8155-e17e23b71215', $q$Instant Website Review$q$, $q$Generates a one-page SEO score and grade breakdown for any URL covering on-page, mobile, backlinks, social, and local SEO factors.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('72ffb4a5-e2e0-4903-8155-e17e23b71215', $q$Site Crawl$q$, $q$Crawls an entire domain to surface technical SEO issues such as broken links, duplicate content, and missing metadata.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('72ffb4a5-e2e0-4903-8155-e17e23b71215', $q$Keyword Tracking$q$, $q$Tracks ranking positions for target keywords across chosen search engines and locations, including city and region-level localization.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('72ffb4a5-e2e0-4903-8155-e17e23b71215', $q$Competitor Analysis$q$, $q$Compares a site's visibility, keywords, and backlink profile against named competitor domains.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('72ffb4a5-e2e0-4903-8155-e17e23b71215', $q$Backlink Monitoring$q$, $q$Tracks changes to a site's backlink profile to flag lost links and new link opportunities.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('72ffb4a5-e2e0-4903-8155-e17e23b71215', $q$White-Label Reporting$q$, $q$Lets agencies rebrand PDF audit and keyword reports with their own logo and colors for client delivery.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('72ffb4a5-e2e0-4903-8155-e17e23b71215', $q$Google Integrations$q$, $q$Connects to Google Analytics and Search Console to pair crawl findings with real traffic and query data.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('72ffb4a5-e2e0-4903-8155-e17e23b71215', $q$Browser Extension$q$, $q$A Chrome extension that runs an instant website review for any page a user is currently browsing.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('72ffb4a5-e2e0-4903-8155-e17e23b71215', $q$Simple, plain-language scorecards that are easy to hand to non-technical stakeholders$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('72ffb4a5-e2e0-4903-8155-e17e23b71215', $q$White-label reporting is well suited to agency client work$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('72ffb4a5-e2e0-4903-8155-e17e23b71215', $q$Combines technical crawl data with real Google Analytics and Search Console metrics$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('72ffb4a5-e2e0-4903-8155-e17e23b71215', $q$Localized keyword tracking down to city and region level$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('72ffb4a5-e2e0-4903-8155-e17e23b71215', $q$14-day free trial available on every paid plan$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('72ffb4a5-e2e0-4903-8155-e17e23b71215', $q$No free-forever tier for ongoing use beyond the trial period$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('72ffb4a5-e2e0-4903-8155-e17e23b71215', $q$Keyword and competitor tracking limits can feel restrictive on the Pro plan for larger portfolios$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('72ffb4a5-e2e0-4903-8155-e17e23b71215', $q$Less depth in backlink index size and content research compared to larger suites like Semrush or Ahrefs$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('72ffb4a5-e2e0-4903-8155-e17e23b71215', $q$Enterprise pricing is not published and requires a sales conversation$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('72ffb4a5-e2e0-4903-8155-e17e23b71215', $q$What does WooRank do?$q$, $q$WooRank audits a website for SEO, mobile usability, and technical issues, then provides ongoing keyword tracking, backlink monitoring, and white-label reporting for agencies and marketers.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('72ffb4a5-e2e0-4903-8155-e17e23b71215', $q$How much does WooRank cost?$q$, $q$WooRank's Pro plan starts at 79.99 dollars per month, Premium is 199.99 dollars per month, and Enterprise pricing is custom-quoted based on needs.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('72ffb4a5-e2e0-4903-8155-e17e23b71215', $q$Does WooRank offer a free trial?$q$, $q$Yes, WooRank offers a 14-day free trial on its paid plans so users can test the site review, crawl, and keyword tools before subscribing.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('72ffb4a5-e2e0-4903-8155-e17e23b71215', $q$Is WooRank good for agencies?$q$, $q$Yes, WooRank's white-label PDF reporting and multi-site management features are specifically designed for digital marketing agencies handling several client accounts.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('72ffb4a5-e2e0-4903-8155-e17e23b71215', $q$Does WooRank track keyword rankings?$q$, $q$Yes, its Keyword Tool tracks ranking positions across search engines and can localize tracking to a specific country, region, or city.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('72ffb4a5-e2e0-4903-8155-e17e23b71215', $q$Can WooRank connect to Google Analytics?$q$, $q$Yes, WooRank integrates with both Google Analytics and Google Search Console to combine crawl findings with real traffic and search performance data.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('72ffb4a5-e2e0-4903-8155-e17e23b71215', $q$Who founded WooRank and where is it based?$q$, $q$WooRank was founded in 2010 and is headquartered in Brussels, Belgium.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('72ffb4a5-e2e0-4903-8155-e17e23b71215', $q$Is WooRank suitable for beginners?$q$, $q$Yes, its instant review scorecard is designed to explain SEO issues in plain language, making it approachable for small business owners without technical SEO backgrounds.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('72ffb4a5-e2e0-4903-8155-e17e23b71215', $q$Client SEO audits for agencies$q$, $q$Agencies run white-labeled site reviews and crawls to diagnose issues and present branded findings to clients.$q$, $q$Digital marketing agencies$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('72ffb4a5-e2e0-4903-8155-e17e23b71215', $q$Small business site health checks$q$, $q$Business owners run instant reviews to understand why their site is not ranking and get prioritized fix recommendations.$q$, $q$Small business owners$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('72ffb4a5-e2e0-4903-8155-e17e23b71215', $q$Local keyword rank tracking$q$, $q$Marketers track rankings for target keywords across specific cities or regions to measure local SEO progress.$q$, $q$Local SEO marketers$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('72ffb4a5-e2e0-4903-8155-e17e23b71215', $q$Pro$q$, $q$$79.99$q$, $q$monthly$q$, NULL, $q$["Instant website review","Site crawl","Keyword tracking","Competitor comparison","14-day free trial"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('72ffb4a5-e2e0-4903-8155-e17e23b71215', $q$Premium$q$, $q$$199.99$q$, $q$monthly$q$, NULL, $q$["Everything in Pro","Higher keyword and competitor limits","Expanded backlink monitoring","White-label PDF reports"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('72ffb4a5-e2e0-4903-8155-e17e23b71215', $q$Enterprise$q$, $q$Custom$q$, $q$custom$q$, NULL, $q$["Custom volume and seat limits","Dedicated support","Advanced reporting for large agencies"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('72ffb4a5-e2e0-4903-8155-e17e23b71215', $q$overview$q$, $q$What Is WooRank$q$, 2, ARRAY[$q$WooRank is a website review and SEO audit platform that scans a URL and returns a graded, easy-to-read scorecard covering on-page SEO, mobile friendliness, site speed signals, backlinks, and social presence. Founded in 2010 in Brussels, Belgium, the company built its reputation on making SEO health checks accessible to non-specialists as much as to professional marketers.$q$, $q$The platform serves two overlapping audiences: small business owners who want a plain-language explanation of why their site is not ranking, and digital marketing agencies who need repeatable, brandable audit reports to show clients. Its core workflow starts with a single-page instant review, then expands into ongoing site crawls and keyword tracking for users who upgrade to a paid plan.$q$, $q$WooRank connects to Google Analytics and Google Search Console so that crawl-based technical findings can be viewed alongside real traffic and query data, giving teams a combined picture of what search engines see and how visitors actually behave on the site.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('72ffb4a5-e2e0-4903-8155-e17e23b71215', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Site Crawl performs a full technical audit of a domain, flagging broken links, missing metadata, duplicate content, slow-loading pages, and accessibility issues so teams can prioritize fixes by impact.$q$, $q$The Keyword Tool tracks ranking positions across search engines and locations, letting users localize tracking to a specific country, region, or city and compare movement against named competitor domains over time.$q$, $q$Backlink monitoring and competitive analysis tools show link profile changes and benchmark a site's visibility against rivals, while white-label PDF reporting lets agencies rebrand findings for client delivery under their own name.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('72ffb4a5-e2e0-4903-8155-e17e23b71215', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$WooRank sells three subscription tiers with a 14-day free trial on each. The Pro plan starts at 79.99 dollars per month and covers core site review, crawl, and keyword tracking needs for a single site or small portfolio.$q$, $q$The Premium plan is priced at 199.99 dollars per month and raises limits on tracked keywords, competitor comparisons, and reviewed domains for agencies managing multiple clients.$q$, $q$An Enterprise plan is available at custom pricing for organizations that need higher volume, additional seats, or dedicated support beyond what Premium offers.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6741ec68-b40f-4b14-9d8b-2af8c98c0e2f', $q$One-Click Blog Generation$q$, $q$Produces a structured long-form blog draft from a topic or outline using large language models.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6741ec68-b40f-4b14-9d8b-2af8c98c0e2f', $q$Long-Form Editor$q$, $q$A built-in writing editor for refining AI-generated drafts before publishing.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6741ec68-b40f-4b14-9d8b-2af8c98c0e2f', $q$Keyword Assistant$q$, $q$Suggests and tracks target search keywords to help writers optimize drafts for SEO.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6741ec68-b40f-4b14-9d8b-2af8c98c0e2f', $q$Content Templates$q$, $q$Pre-built templates for formats beyond blog posts, including ad copy, product descriptions, and social captions.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6741ec68-b40f-4b14-9d8b-2af8c98c0e2f', $q$WordHero Art$q$, $q$AI image generation tool for creating visuals to accompany written content.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6741ec68-b40f-4b14-9d8b-2af8c98c0e2f', $q$AI Chat with Wizard Mode$q$, $q$A conversational AI assistant for brainstorming topics, angles, and outlines before drafting.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6741ec68-b40f-4b14-9d8b-2af8c98c0e2f', $q$Multi-Language Support$q$, $q$Supports content generation in 108 languages for non-English publishing needs.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6741ec68-b40f-4b14-9d8b-2af8c98c0e2f', $q$Style Adaptation$q$, $q$Aims to match generated content to an individual user's established writing voice.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6741ec68-b40f-4b14-9d8b-2af8c98c0e2f', $q$Lower entry price than many competing AI writing platforms$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6741ec68-b40f-4b14-9d8b-2af8c98c0e2f', $q$One-click workflow is fast for producing first drafts of blog content$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6741ec68-b40f-4b14-9d8b-2af8c98c0e2f', $q$Includes image generation and keyword assistance in the same subscription$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6741ec68-b40f-4b14-9d8b-2af8c98c0e2f', $q$Broad language support for non-English content needs$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6741ec68-b40f-4b14-9d8b-2af8c98c0e2f', $q$14-day money-back guarantee reduces trial risk$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6741ec68-b40f-4b14-9d8b-2af8c98c0e2f', $q$AI-generated drafts typically require human editing for accuracy and voice consistency$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6741ec68-b40f-4b14-9d8b-2af8c98c0e2f', $q$No permanent free plan, only a refund window$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6741ec68-b40f-4b14-9d8b-2af8c98c0e2f', $q$Infinity plan team size is capped at five members$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6741ec68-b40f-4b14-9d8b-2af8c98c0e2f', $q$Smaller company and community compared to larger AI writing platforms$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6741ec68-b40f-4b14-9d8b-2af8c98c0e2f', $q$What is WordHero used for?$q$, $q$WordHero is used to generate blog posts, marketing copy, and images using AI, primarily for content creators, bloggers, and marketers who want faster first drafts.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6741ec68-b40f-4b14-9d8b-2af8c98c0e2f', $q$How much does WordHero cost?$q$, $q$WordHero's Creator plan starts at 29 dollars per month billed annually, and the Infinity team plan starts at 79 dollars per month billed annually.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6741ec68-b40f-4b14-9d8b-2af8c98c0e2f', $q$Does WordHero offer a free trial?$q$, $q$WordHero does not offer a permanent free plan but backs subscriptions with a 14-day money-back guarantee.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6741ec68-b40f-4b14-9d8b-2af8c98c0e2f', $q$Who founded WordHero?$q$, $q$WordHero was founded in July 2021 by Jeff Tay and is operated by J1 Holdings, a Singapore-based technology company.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6741ec68-b40f-4b14-9d8b-2af8c98c0e2f', $q$Can WordHero generate images?$q$, $q$Yes, WordHero includes an AI image generation feature called WordHero Art.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6741ec68-b40f-4b14-9d8b-2af8c98c0e2f', $q$How many languages does WordHero support?$q$, $q$WordHero advertises support for content generation in 108 languages.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6741ec68-b40f-4b14-9d8b-2af8c98c0e2f', $q$Is WordHero good for SEO content?$q$, $q$WordHero includes a keyword assistant in its long-form editor to help writers work target search terms into drafts.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6741ec68-b40f-4b14-9d8b-2af8c98c0e2f', $q$Does WordHero support teams?$q$, $q$The Infinity plan supports up to five team members with unlimited Enhanced Mode access.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('6741ec68-b40f-4b14-9d8b-2af8c98c0e2f', $q$Blog content production$q$, $q$Bloggers and publishers generate first-draft long-form posts quickly, then edit them in the built-in editor.$q$, $q$Bloggers and content publishers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('6741ec68-b40f-4b14-9d8b-2af8c98c0e2f', $q$Marketing copy generation$q$, $q$Marketers use templates for ad copy, product descriptions, and social captions alongside longer content.$q$, $q$Digital marketers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('6741ec68-b40f-4b14-9d8b-2af8c98c0e2f', $q$Multilingual content creation$q$, $q$Businesses generate content in non-English markets using WordHero's 108-language support.$q$, $q$International content teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('6741ec68-b40f-4b14-9d8b-2af8c98c0e2f', $q$Creator$q$, $q$$29/month (annual) or $49/month (monthly)$q$, $q$monthly or annual$q$, NULL, $q$["Unlimited content generation","160,000 Enhanced Mode tokens","Long-form editor","Keyword assistant","14-day money-back guarantee"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('6741ec68-b40f-4b14-9d8b-2af8c98c0e2f', $q$Infinity$q$, $q$$79/month (annual) or $99/month (monthly)$q$, $q$monthly or annual$q$, NULL, $q$["Up to 5 team members","Unlimited Enhanced Mode access","Everything in Creator","WordHero Art image generation"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('6741ec68-b40f-4b14-9d8b-2af8c98c0e2f', $q$overview$q$, $q$What Is WordHero$q$, 2, ARRAY[$q$WordHero is an AI writing tool focused on generating blog posts and marketing content quickly, using large language models to produce first drafts that a writer can then edit and publish. It was launched in July 2021 by founder Jeff Tay and is operated by J1 Holdings, a Singapore-based technology company.$q$, $q$The product targets content creators, bloggers, marketers, business owners, and digital publishers who want to accelerate their writing workflow without hiring additional writers for every piece of content. Its workflow centers on one-click blog generation, supported by a long-form editor, template library, and an AI chat mode for brainstorming.$q$, $q$WordHero positions itself as adapting to an individual writer's existing voice and style, rather than producing generic, uniformly toned AI output, and supports content generation across 108 languages.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('6741ec68-b40f-4b14-9d8b-2af8c98c0e2f', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$One-click blog post generation produces a structured long-form draft from a topic or outline, which can then be refined in WordHero's built-in editor.$q$, $q$A keyword assistant helps writers incorporate target search terms into drafts for SEO purposes, while a library of pre-built templates covers shorter formats like ad copy, product descriptions, and social captions.$q$, $q$WordHero Art adds AI image generation for accompanying visuals, and an AI chat feature with wizard mode supports brainstorming topics and outlines before a draft is created.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('6741ec68-b40f-4b14-9d8b-2af8c98c0e2f', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$WordHero offers two subscription tiers, both backed by a 14-day money-back guarantee. The Creator plan is 29 dollars per month billed annually, or 49 dollars per month billed monthly, and includes unlimited content generation with 160,000 Enhanced Mode tokens for higher-quality output.$q$, $q$The Infinity plan is designed for small teams of up to five members and costs 79 dollars per month billed annually, or 99 dollars per month billed monthly, with unlimited Enhanced Mode access rather than a token allowance.$q$, $q$There is no permanent free tier, but the money-back guarantee functions as a low-risk trial period for new subscribers.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8741e733-7b13-489c-8696-9d50fbf35b42', $q$Gutenberg Block Editor$q$, $q$A native block-based editor for building pages and posts without needing to write code.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8741e733-7b13-489c-8696-9d50fbf35b42', $q$Plugin Architecture$q$, $q$An extensible system allowing developers to add functionality such as ecommerce, forms, or SEO tools without modifying core files.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8741e733-7b13-489c-8696-9d50fbf35b42', $q$Theme System$q$, $q$A theming layer that controls site design and layout, with thousands of free and premium themes available.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8741e733-7b13-489c-8696-9d50fbf35b42', $q$Self-Hosted Control$q$, $q$Full control over server configuration, custom code, and data since the software runs on hosting the user chooses.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8741e733-7b13-489c-8696-9d50fbf35b42', $q$Open-Source Licensing$q$, $q$Released under the GPLv2 or later, allowing free use, modification, and redistribution including for commercial projects.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8741e733-7b13-489c-8696-9d50fbf35b42', $q$Multisite Support$q$, $q$Built-in capability to run a network of multiple sites from a single WordPress installation.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8741e733-7b13-489c-8696-9d50fbf35b42', $q$Large Plugin and Theme Directory$q$, $q$An official directory of free plugins and themes reviewed and hosted on WordPress.org.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8741e733-7b13-489c-8696-9d50fbf35b42', $q$REST API$q$, $q$A built-in API that allows WordPress content to be accessed and managed programmatically for headless or custom front-end setups.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8741e733-7b13-489c-8696-9d50fbf35b42', $q$Completely free and open source with no licensing cost$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8741e733-7b13-489c-8696-9d50fbf35b42', $q$Enormous ecosystem of themes and plugins covering nearly any website need$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8741e733-7b13-489c-8696-9d50fbf35b42', $q$Full control over hosting, code, and configuration since it is self-hosted$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8741e733-7b13-489c-8696-9d50fbf35b42', $q$Large global community and extensive documentation and support forums$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8741e733-7b13-489c-8696-9d50fbf35b42', $q$No vendor lock-in since the software and data can be moved to any compatible host$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8741e733-7b13-489c-8696-9d50fbf35b42', $q$Requires the user to source and manage their own hosting, unlike managed platforms$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8741e733-7b13-489c-8696-9d50fbf35b42', $q$Security and updates are the site owner's responsibility unless a managed host or maintenance service is used$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8741e733-7b13-489c-8696-9d50fbf35b42', $q$Quality of themes and plugins varies widely since many are third-party contributions$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8741e733-7b13-489c-8696-9d50fbf35b42', $q$Can require technical knowledge or a developer for advanced customization or troubleshooting$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8741e733-7b13-489c-8696-9d50fbf35b42', $q$Is WordPress free?$q$, $q$Yes, the WordPress software itself is free and open source. Costs come from separately purchased hosting, domains, and any premium themes or plugins.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8741e733-7b13-489c-8696-9d50fbf35b42', $q$What is the difference between WordPress.org and WordPress.com?$q$, $q$WordPress.org distributes the free, self-hosted open-source software that you install on your own hosting. WordPress.com is a separate, commercial managed hosting service operated by Automattic that runs the same underlying software as a paid product.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8741e733-7b13-489c-8696-9d50fbf35b42', $q$Who created WordPress?$q$, $q$WordPress was created in 2003 by Matt Mullenweg and Mike Little as a fork of the b2/cafelog blogging platform.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8741e733-7b13-489c-8696-9d50fbf35b42', $q$What license is WordPress released under?$q$, $q$WordPress is released under the GNU General Public License version 2 or later (GPLv2+), which allows free use, modification, and redistribution.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8741e733-7b13-489c-8696-9d50fbf35b42', $q$Do I need hosting to use WordPress.org software?$q$, $q$Yes, self-hosted WordPress requires you to obtain web hosting from a third-party provider and install the software yourself.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8741e733-7b13-489c-8696-9d50fbf35b42', $q$Can WordPress be used for ecommerce?$q$, $q$Yes, WordPress supports ecommerce through plugins such as WooCommerce, which is widely used to turn a WordPress site into an online store.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8741e733-7b13-489c-8696-9d50fbf35b42', $q$How many websites use WordPress?$q$, $q$WordPress powers a majority of all websites on the internet that run on a known content management system, making it the most widely used CMS.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8741e733-7b13-489c-8696-9d50fbf35b42', $q$Does WordPress require coding knowledge?$q$, $q$Basic site building can be done without coding using themes and the block editor, but advanced customization typically benefits from developer knowledge of PHP, HTML, CSS, or JavaScript.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('8741e733-7b13-489c-8696-9d50fbf35b42', $q$Self-hosted business websites$q$, $q$Organizations install WordPress on their own hosting to fully control design, code, and data for their website.$q$, $q$Small businesses and developers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('8741e733-7b13-489c-8696-9d50fbf35b42', $q$Blogging and publishing$q$, $q$Writers and publications use WordPress's editing tools and content organization features to run blogs and media sites.$q$, $q$Bloggers and publishers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('8741e733-7b13-489c-8696-9d50fbf35b42', $q$Custom ecommerce stores$q$, $q$Merchants combine WordPress with plugins like WooCommerce to build customizable online stores without vendor lock-in.$q$, $q$Ecommerce merchants and agencies$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('8741e733-7b13-489c-8696-9d50fbf35b42', $q$WordPress Software$q$, $q$Free$q$, $q$n/a$q$, NULL, $q$["Core CMS software","Gutenberg block editor","Free plugin and theme directory access","Self-hosted installation","Community support forums"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('8741e733-7b13-489c-8696-9d50fbf35b42', $q$overview$q$, $q$What Is WordPress$q$, 2, ARRAY[$q$WordPress is a free, open-source content management system first released in 2003 by Matt Mullenweg and Mike Little as a fork of the b2/cafelog blogging platform. It is distributed through WordPress.org and licensed under the GPLv2 or later, meaning the software can be freely used, modified, and redistributed by anyone, including for commercial projects.$q$, $q$WordPress.org is not a hosting company or a paid product. It is the home of the open-source software project, offering the core CMS download, a directory of free themes and plugins, documentation, and community support forums. Anyone who wants to run WordPress must supply their own web hosting and install the software themselves, which is why this is often called self-hosted WordPress to distinguish it from the managed WordPress.com service.$q$, $q$This self-hosted model gives site owners full control over server configuration, custom code, and data, at the cost of needing to manage updates, security, and hosting relationships themselves rather than relying on a single managed provider.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('8741e733-7b13-489c-8696-9d50fbf35b42', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$The core WordPress software includes a block-based editor called Gutenberg for building pages and posts, a theming system for controlling site design, and a plugin architecture that lets developers extend functionality without modifying core code.$q$, $q$Its ecosystem includes tens of thousands of free and premium plugins covering ecommerce, SEO, forms, security, caching, and page building, alongside thousands of free and paid themes, making it possible to build nearly any type of website on top of the same core platform.$q$, $q$Because the software is open source, developers can inspect and modify any part of it, build custom plugins and themes, and avoid dependence on a single vendor for the platform's continued existence.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('8741e733-7b13-489c-8696-9d50fbf35b42', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$The WordPress software itself is entirely free to download, install, and use, with no licensing fees, subscription tiers, or seat limits, since it is released under the GPL open-source license.$q$, $q$Real-world costs come from elements outside the software: web hosting from a third-party provider, a domain name, and optionally premium themes, premium plugins, and developer or maintenance services.$q$, $q$This is a key difference from WordPress.com, which packages the same underlying WordPress software into a managed, paid hosting product with its own subscription tiers.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('8741e733-7b13-489c-8696-9d50fbf35b42', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('8741e733-7b13-489c-8696-9d50fbf35b42', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6b5c71e6-e1cf-4f55-9339-d6d644c3f1a6', $q$Free Starter Plan$q$, $q$A no-credit-card-required free tier for launching a basic WordPress.com site with WordPress.com branding.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6b5c71e6-e1cf-4f55-9339-d6d644c3f1a6', $q$Managed Hosting$q$, $q$Automattic handles server infrastructure, backups, security, and core software updates on the customer's behalf.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6b5c71e6-e1cf-4f55-9339-d6d644c3f1a6', $q$Custom Domains$q$, $q$Paid plans include a free custom domain for the first year, replacing the default wordpress.com subdomain.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6b5c71e6-e1cf-4f55-9339-d6d644c3f1a6', $q$Premium Themes$q$, $q$Access to a curated library of premium designs starting at the Premium plan tier.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6b5c71e6-e1cf-4f55-9339-d6d644c3f1a6', $q$Plugin and Theme Uploads$q$, $q$Business plan and above unlock full plugin installation and custom theme uploads, matching self-hosted flexibility.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6b5c71e6-e1cf-4f55-9339-d6d644c3f1a6', $q$Integrated Ecommerce$q$, $q$The Commerce plan adds tools for selling products and services directly through the site.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6b5c71e6-e1cf-4f55-9339-d6d644c3f1a6', $q$Jetpack Integration$q$, $q$Built-in access to Jetpack features for security, performance, and site stats without separate setup.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6b5c71e6-e1cf-4f55-9339-d6d644c3f1a6', $q$Automattic for Agencies$q$, $q$Enterprise and agency-focused programs offering custom pricing and management tools for larger site portfolios.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6b5c71e6-e1cf-4f55-9339-d6d644c3f1a6', $q$Genuinely free tier available with no credit card required$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6b5c71e6-e1cf-4f55-9339-d6d644c3f1a6', $q$Fully managed hosting removes the need to handle server maintenance or security patching$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6b5c71e6-e1cf-4f55-9339-d6d644c3f1a6', $q$Bundles domain, hosting, and security into one predictable subscription price$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6b5c71e6-e1cf-4f55-9339-d6d644c3f1a6', $q$Business and Commerce tiers offer nearly the same flexibility as self-hosted WordPress$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6b5c71e6-e1cf-4f55-9339-d6d644c3f1a6', $q$Backed by Automattic's large-scale infrastructure and Jetpack feature set$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6b5c71e6-e1cf-4f55-9339-d6d644c3f1a6', $q$Free plan carries WordPress.com branding, no custom domain, and no plugin support$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6b5c71e6-e1cf-4f55-9339-d6d644c3f1a6', $q$Plugin and theme upload flexibility is locked behind the higher-priced Business and Commerce plans$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6b5c71e6-e1cf-4f55-9339-d6d644c3f1a6', $q$Less control over server configuration than fully self-hosted WordPress.org$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6b5c71e6-e1cf-4f55-9339-d6d644c3f1a6', $q$Costs can add up when moving from free to Business or Commerce tiers for full functionality$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6b5c71e6-e1cf-4f55-9339-d6d644c3f1a6', $q$Is WordPress.com free?$q$, $q$WordPress.com offers a genuinely free plan with no credit card required, though it has limitations like no custom domain, no plugin installation, and WordPress.com branding.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6b5c71e6-e1cf-4f55-9339-d6d644c3f1a6', $q$What is the difference between WordPress.com and WordPress.org?$q$, $q$WordPress.com is a paid, managed hosting service run by Automattic that handles infrastructure for you. WordPress.org is the free, self-hosted open-source software that you install on hosting of your choice.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6b5c71e6-e1cf-4f55-9339-d6d644c3f1a6', $q$How much do WordPress.com paid plans cost?$q$, $q$As of mid-2026, paid plans range from around 4 dollars per month for Personal up to around 45 dollars per month for Commerce, all billed annually, with higher monthly-billed pricing.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6b5c71e6-e1cf-4f55-9339-d6d644c3f1a6', $q$Can I install plugins on WordPress.com?$q$, $q$Plugin installation is only available on the Business plan and above; lower tiers do not support custom plugins.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6b5c71e6-e1cf-4f55-9339-d6d644c3f1a6', $q$Who owns WordPress.com?$q$, $q$WordPress.com is operated by Automattic, the company co-founded by WordPress creator Matt Mullenweg in 2005.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6b5c71e6-e1cf-4f55-9339-d6d644c3f1a6', $q$Does WordPress.com support ecommerce?$q$, $q$Yes, the Commerce plan includes integrated ecommerce tools for selling products and services directly through the site.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6b5c71e6-e1cf-4f55-9339-d6d644c3f1a6', $q$Do WordPress.com plans include a custom domain?$q$, $q$Paid plans include a free custom domain for the first year; the free plan uses a wordpress.com subdomain.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6b5c71e6-e1cf-4f55-9339-d6d644c3f1a6', $q$Is WordPress.com good for beginners?$q$, $q$Yes, its managed hosting model removes the technical setup burden of self-hosted WordPress, making it approachable for users without server management experience.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('6b5c71e6-e1cf-4f55-9339-d6d644c3f1a6', $q$Hassle-free personal blogging$q$, $q$Individuals launch a blog on the free or Personal plan without managing hosting or security themselves.$q$, $q$Bloggers and hobbyists$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('6b5c71e6-e1cf-4f55-9339-d6d644c3f1a6', $q$Managed small business websites$q$, $q$Small businesses use Business or Commerce plans to get plugin flexibility and ecommerce without server management.$q$, $q$Small business owners$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('6b5c71e6-e1cf-4f55-9339-d6d644c3f1a6', $q$Agency-managed client sites$q$, $q$Agencies use Automattic for Agencies programs to manage multiple client WordPress.com sites under custom pricing.$q$, $q$Web design agencies$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('6b5c71e6-e1cf-4f55-9339-d6d644c3f1a6', $q$Free$q$, $q$$0$q$, $q$n/a$q$, NULL, $q$["WordPress.com subdomain","Basic themes","WordPress.com branding and ads","No plugin installation"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('6b5c71e6-e1cf-4f55-9339-d6d644c3f1a6', $q$Personal$q$, $q$$4/month (annual) or $9/month (monthly)$q$, $q$monthly or annual$q$, NULL, $q$["Free custom domain for first year","Ad removal","Email and live chat support"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('6b5c71e6-e1cf-4f55-9339-d6d644c3f1a6', $q$Premium$q$, $q$$8/month (annual) or $18/month (monthly)$q$, $q$monthly or annual$q$, NULL, $q$["Premium themes","More storage","Everything in Personal"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('6b5c71e6-e1cf-4f55-9339-d6d644c3f1a6', $q$Business$q$, $q$$25/month (annual) or $40/month (monthly)$q$, $q$monthly or annual$q$, NULL, $q$["Plugin installation","Custom theme uploads","200GB storage"]$q$::jsonb, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('6b5c71e6-e1cf-4f55-9339-d6d644c3f1a6', $q$Commerce$q$, $q$$45/month (annual) or $70/month (monthly)$q$, $q$monthly or annual$q$, NULL, $q$["Integrated ecommerce tools","Everything in Business"]$q$::jsonb, 4);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('6b5c71e6-e1cf-4f55-9339-d6d644c3f1a6', $q$overview$q$, $q$What Is WordPress.com$q$, 2, ARRAY[$q$WordPress.com is a managed hosting platform operated by Automattic, the company co-founded by WordPress creator Matt Mullenweg in 2005. It runs the same core WordPress software distributed by WordPress.org, but as a fully hosted, paid service rather than software you install yourself.$q$, $q$The platform is designed for individuals, bloggers, small businesses, and organizations that want a WordPress-powered website without managing their own hosting, security patches, or backups. Automattic handles the technical infrastructure, and customers choose a plan based on how much customization, storage, and ecommerce capability they need.$q$, $q$WordPress.com should not be confused with WordPress.org, the free open-source software project. WordPress.com is a commercial product with tiered subscription pricing, ads on its free plan, and restrictions on plugins and custom code that only lift at higher paid tiers.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('6b5c71e6-e1cf-4f55-9339-d6d644c3f1a6', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$The free plan lets anyone start a WordPress.com site with no credit card, though it includes WordPress.com branding, no custom domain, and no plugin support.$q$, $q$Paid plans progressively unlock a free custom domain, premium themes, more storage, and at the Business tier and above, full plugin installation and custom theme uploads, effectively matching the flexibility of self-hosted WordPress.$q$, $q$The Commerce plan adds integrated ecommerce functionality for selling products or services, while all paid plans bundle hosting, domain registration, privacy protection, and security into a single subscription.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('6b5c71e6-e1cf-4f55-9339-d6d644c3f1a6', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$WordPress.com offers a free plan with no credit card required, alongside four paid tiers. As of mid-2026, Personal starts around 4 dollars per month billed annually, Premium around 8 dollars per month annually, Business around 25 dollars per month annually, and Commerce around 45 dollars per month annually, each roughly doubling in monthly-billed pricing.$q$, $q$The Business plan is the key upgrade threshold since it is the first tier to allow plugin installation and custom theme uploads with 200GB of storage, while Commerce builds on that with ecommerce-specific tools.$q$, $q$Enterprise customers with large-scale or agency needs can access custom pricing through Automattic's dedicated enterprise and agency programs rather than the standard self-service tiers.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a5fa585a-6104-495a-a452-912fb307c35f', $q$AI Rewrite Suggestions$q$, $q$Suggests alternative phrasings for selected sentences to improve clarity, tone, or length.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a5fa585a-6104-495a-a452-912fb307c35f', $q$Tone Adjustment$q$, $q$Shifts writing between casual and formal registers based on the intended audience.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a5fa585a-6104-495a-a452-912fb307c35f', $q$Spices$q$, $q$Generates contextual content additions such as examples, counterarguments, or statistics to strengthen a draft.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a5fa585a-6104-495a-a452-912fb307c35f', $q$Wordtune Read$q$, $q$Summarizes long articles or documents into key points for faster reading.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a5fa585a-6104-495a-a452-912fb307c35f', $q$Grammar and Spelling Correction$q$, $q$Unlimited text correction included on every plan, including the free tier.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a5fa585a-6104-495a-a452-912fb307c35f', $q$Browser Extension$q$, $q$Works inside Gmail, Google Docs, LinkedIn, and most web-based text fields.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a5fa585a-6104-495a-a452-912fb307c35f', $q$Standalone Apps$q$, $q$Available as web and desktop applications in addition to the browser extension.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a5fa585a-6104-495a-a452-912fb307c35f', $q$Teams Billing$q$, $q$Centralized billing and business support for organizations equipping multiple writers under one account.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a5fa585a-6104-495a-a452-912fb307c35f', $q$Context-aware rewriting goes beyond basic grammar checking$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a5fa585a-6104-495a-a452-912fb307c35f', $q$Free plan includes unlimited grammar correction plus a daily allotment of rewrites$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a5fa585a-6104-495a-a452-912fb307c35f', $q$Works across most popular writing surfaces via browser extension$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a5fa585a-6104-495a-a452-912fb307c35f', $q$Wordtune Read adds document summarization on top of writing assistance$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a5fa585a-6104-495a-a452-912fb307c35f', $q$Backed by AI21 Labs' own large language model research$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a5fa585a-6104-495a-a452-912fb307c35f', $q$Free plan's daily rewrite and Spice limits are restrictive for heavy users$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a5fa585a-6104-495a-a452-912fb307c35f', $q$Unlimited usage requires the higher-priced Unlimited or Teams plan$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a5fa585a-6104-495a-a452-912fb307c35f', $q$Primarily focused on English-language writing$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a5fa585a-6104-495a-a452-912fb307c35f', $q$Rewrite quality can vary depending on sentence complexity and context$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a5fa585a-6104-495a-a452-912fb307c35f', $q$What is Wordtune used for?$q$, $q$Wordtune is used to rewrite and paraphrase sentences, adjust tone, summarize documents, and correct grammar using AI, primarily through a browser extension.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a5fa585a-6104-495a-a452-912fb307c35f', $q$Who makes Wordtune?$q$, $q$Wordtune is made by AI21 Labs, an Israeli AI company founded in 2017 by Yoav Shoham, Ori Goshen, and Amnon Shashua.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a5fa585a-6104-495a-a452-912fb307c35f', $q$Is Wordtune free?$q$, $q$Wordtune has a free plan with 10 daily rewrites and Spices, 3 monthly summaries, and unlimited grammar correction. Paid plans start at 13.99 dollars per month for more usage.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a5fa585a-6104-495a-a452-912fb307c35f', $q$What are Wordtune Spices?$q$, $q$Spices are short AI-generated content additions, such as examples, counterarguments, or statistics, that can be inserted directly into a draft.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a5fa585a-6104-495a-a452-912fb307c35f', $q$Does Wordtune work in Gmail and Google Docs?$q$, $q$Yes, Wordtune's browser extension works inside Gmail, Google Docs, LinkedIn, and most web-based text fields.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a5fa585a-6104-495a-a452-912fb307c35f', $q$What is Wordtune Read?$q$, $q$Wordtune Read is a feature that summarizes long articles or documents into key points.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a5fa585a-6104-495a-a452-912fb307c35f', $q$How much is Wordtune for teams?$q$, $q$The Teams plan is priced at 7.99 dollars per seat per month when billed annually, including centralized billing and Unlimited plan features.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a5fa585a-6104-495a-a452-912fb307c35f', $q$When was Wordtune launched?$q$, $q$Wordtune was launched on October 27, 2020, as AI21 Labs' first consumer product.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('a5fa585a-6104-495a-a452-912fb307c35f', $q$Email and message polishing$q$, $q$Professionals use Wordtune's browser extension to rewrite and adjust the tone of emails and messages before sending.$q$, $q$Business professionals$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('a5fa585a-6104-495a-a452-912fb307c35f', $q$Content editing for writers$q$, $q$Writers use rewrite suggestions and Spices to strengthen drafts with alternative phrasing and supporting content.$q$, $q$Content writers and marketers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('a5fa585a-6104-495a-a452-912fb307c35f', $q$Fast document summarization$q$, $q$Readers use Wordtune Read to condense long articles or reports into key points for quicker review.$q$, $q$Researchers and knowledge workers$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('a5fa585a-6104-495a-a452-912fb307c35f', $q$Free$q$, $q$$0$q$, $q$n/a$q$, NULL, $q$["10 rewrites and Spices per day","3 monthly summaries","Unlimited text corrections"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('a5fa585a-6104-495a-a452-912fb307c35f', $q$Advanced$q$, $q$$13.99$q$, $q$monthly$q$, NULL, $q$["30 rewrites and Spices per day","15 monthly summaries","Unlimited text corrections and recommendations"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('a5fa585a-6104-495a-a452-912fb307c35f', $q$Unlimited$q$, $q$$19.99$q$, $q$monthly$q$, NULL, $q$["Unlimited rewrites and Spices","Unlimited summaries","Premium support"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('a5fa585a-6104-495a-a452-912fb307c35f', $q$Teams$q$, $q$$7.99/seat$q$, $q$monthly (billed annually)$q$, NULL, $q$["All Unlimited plan features","Centralized billing","Business support"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('a5fa585a-6104-495a-a452-912fb307c35f', $q$overview$q$, $q$What Is Wordtune$q$, 2, ARRAY[$q$Wordtune is an AI writing assistant built by AI21 Labs, an Israeli AI research company founded in 2017 by Yoav Shoham, Ori Goshen, and Amnon Shashua. Launched in October 2020, Wordtune was AI21 Labs' first product and remains its best-known consumer offering.$q$, $q$The tool goes beyond spelling and grammar checking by using natural language generation to understand the meaning of a sentence and suggest full rewrites, paraphrases, and tone adjustments rather than simple corrections. It works as a browser extension across Gmail, Google Docs, LinkedIn, and most text fields on the web, as well as through standalone web and desktop apps.$q$, $q$Wordtune also includes a reading companion feature, Wordtune Read, that condenses long articles or documents into key points, positioning the product as both a writing and reading productivity tool.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('a5fa585a-6104-495a-a452-912fb307c35f', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Rewrite suggestions offer alternative phrasings for a selected sentence, letting users shorten, expand, formalize, or casualize their writing with a click rather than manually editing.$q$, $q$Spices generate short pieces of contextual content, such as examples, counterarguments, explanations, or statistics, that a writer can insert directly into a draft to strengthen an argument.$q$, $q$Wordtune Read summarizes long articles or documents into key points, and the tool includes unlimited grammar and spelling correction across every plan, including the free tier.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('a5fa585a-6104-495a-a452-912fb307c35f', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Wordtune's Free plan includes 10 rewrites and Spices per day, 3 monthly document summaries, and unlimited text corrections, with no cost.$q$, $q$The Advanced plan costs 13.99 dollars per month and raises the daily limit to 30 rewrites and Spices with 15 monthly summaries, while the Unlimited plan at 19.99 dollars per month removes daily caps entirely and adds premium support.$q$, $q$A Teams plan is priced at 7.99 dollars per seat per month when billed annually, bundling Unlimited features with centralized billing for organizations equipping multiple writers.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('63552ca4-8785-47c6-9aaf-f0643adf97b5', $q$Applicant Tracking System$q$, $q$Manages job postings, candidate pipelines, and hiring team collaboration in one platform.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('63552ca4-8785-47c6-9aaf-f0643adf97b5', $q$Multi-Board Job Distribution$q$, $q$Posts open roles to multiple job boards simultaneously from a single listing.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('63552ca4-8785-47c6-9aaf-f0643adf97b5', $q$AI Recruiting Agent$q$, $q$Auto-sources and pre-screens candidates using AI to reduce manual sourcing work.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('63552ca4-8785-47c6-9aaf-f0643adf97b5', $q$Candidate Sourcing Database$q$, $q$A searchable database of candidate profiles that recruiters can proactively reach out to.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('63552ca4-8785-47c6-9aaf-f0643adf97b5', $q$Video Interviews and Assessments$q$, $q$Optional add-ons for conducting recorded or live video interviews and skills assessments.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('63552ca4-8785-47c6-9aaf-f0643adf97b5', $q$HR Information System$q$, $q$Covers employee onboarding, time-off management, time tracking, and e-signatures.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('63552ca4-8785-47c6-9aaf-f0643adf97b5', $q$Payroll Preparation$q$, $q$Prepares payroll data and integrates with third-party payroll providers.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('63552ca4-8785-47c6-9aaf-f0643adf97b5', $q$Structured Hiring Scorecards$q$, $q$Lets hiring teams evaluate candidates consistently using shared, structured scorecards.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('63552ca4-8785-47c6-9aaf-f0643adf97b5', $q$Combines recruiting and lightweight HR functionality in a single platform$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('63552ca4-8785-47c6-9aaf-f0643adf97b5', $q$AI recruiting agent helps automate candidate sourcing and pre-screening$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('63552ca4-8785-47c6-9aaf-f0643adf97b5', $q$Scales from small businesses up to enterprise-size organizations$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('63552ca4-8785-47c6-9aaf-f0643adf97b5', $q$Global office presence supports multi-region hiring teams$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('63552ca4-8785-47c6-9aaf-f0643adf97b5', $q$Free AI credits included on every plan tier$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('63552ca4-8785-47c6-9aaf-f0643adf97b5', $q$Base Standard plan requires paid add-ons for video interviews, assessments, and texting$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('63552ca4-8785-47c6-9aaf-f0643adf97b5', $q$Pricing is notably higher than some smaller ATS competitors, especially once add-ons are included$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('63552ca4-8785-47c6-9aaf-f0643adf97b5', $q$HR features are less comprehensive than dedicated full-scale HRIS or payroll platforms$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('63552ca4-8785-47c6-9aaf-f0643adf97b5', $q$Enterprise plan pricing is not fully customized, which may not suit very large organizations with complex needs$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('63552ca4-8785-47c6-9aaf-f0643adf97b5', $q$What is Workable used for?$q$, $q$Workable is used as an applicant tracking system for recruiting, and it also includes HR tools for onboarding, time-off management, and payroll preparation.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('63552ca4-8785-47c6-9aaf-f0643adf97b5', $q$How much does Workable cost?$q$, $q$Workable's Standard plan is 299 dollars per month, Premier is 599 dollars per month, and Enterprise is 719 dollars per month, each with a 20 percent discount available for annual billing.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('63552ca4-8785-47c6-9aaf-f0643adf97b5', $q$Who founded Workable?$q$, $q$Workable was founded in June 2012 in Athens, Greece by Nikos Moraitakis and Spyros Magiatis.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('63552ca4-8785-47c6-9aaf-f0643adf97b5', $q$Where is Workable headquartered?$q$, $q$Workable's primary headquarters is in Boston, Massachusetts, with additional offices in Athens, London, and Singapore.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('63552ca4-8785-47c6-9aaf-f0643adf97b5', $q$Does Workable include HR features beyond recruiting?$q$, $q$Yes, Workable includes an HR information system covering onboarding, time-off tracking, time tracking, e-signatures, and payroll preparation.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('63552ca4-8785-47c6-9aaf-f0643adf97b5', $q$Does Workable use AI for recruiting?$q$, $q$Yes, Workable includes an AI recruiting agent that can auto-source and pre-screen candidates, with free AI credits included on all plans.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('63552ca4-8785-47c6-9aaf-f0643adf97b5', $q$Are video interviews included in Workable's base plan?$q$, $q$No, video interviews are an optional paid add-on on the Standard plan but are included in the Premier and Enterprise plans.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('63552ca4-8785-47c6-9aaf-f0643adf97b5', $q$What size companies use Workable?$q$, $q$Workable serves companies ranging from small businesses with around 1 to 20 employees up to enterprises with 1,000 or more employees.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('63552ca4-8785-47c6-9aaf-f0643adf97b5', $q$SMB hiring pipeline management$q$, $q$Small businesses use Workable's ATS to post jobs, screen candidates, and collaborate on hiring decisions.$q$, $q$Small and mid-sized businesses$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('63552ca4-8785-47c6-9aaf-f0643adf97b5', $q$Multi-region recruiting$q$, $q$Growing companies with distributed hiring teams use Workable to manage candidates across multiple offices and countries.$q$, $q$HR and talent acquisition teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('63552ca4-8785-47c6-9aaf-f0643adf97b5', $q$Combined hiring and onboarding workflow$q$, $q$Organizations use Workable to move candidates from offer through onboarding using its integrated HR tools.$q$, $q$HR generalists and people operations teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('63552ca4-8785-47c6-9aaf-f0643adf97b5', $q$Standard$q$, $q$$299/month ($3,588/year annual)$q$, $q$monthly or annual$q$, NULL, $q$["Applicant tracking system","Unlimited active jobs","HR information system","Optional add-ons for texting, video interviews, assessments"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('63552ca4-8785-47c6-9aaf-f0643adf97b5', $q$Premier$q$, $q$$599/month ($7,188/year annual)$q$, $q$monthly or annual$q$, NULL, $q$["Everything in Standard","Included texting, video interviews, assessments, referrals","Included performance and engagement tools"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('63552ca4-8785-47c6-9aaf-f0643adf97b5', $q$Enterprise$q$, $q$$719/month ($8,628/year annual)$q$, $q$monthly or annual$q$, NULL, $q$["Everything in Premier","Single sign-on","Priority support"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('63552ca4-8785-47c6-9aaf-f0643adf97b5', $q$overview$q$, $q$What Is Workable$q$, 2, ARRAY[$q$Workable is an applicant tracking system and HR software platform founded in June 2012 in Athens, Greece by Nikos Moraitakis and Spyros Magiatis, built to give smaller companies access to recruiting technology previously reserved for large enterprises. The company is now headquartered in Boston, Massachusetts, with additional offices in Athens, London, and Singapore.$q$, $q$The platform's core is an applicant tracking system that lets companies post job openings across multiple job boards at once, build a careers page, source candidates from a searchable database, and manage hiring pipelines collaboratively with hiring managers and interviewers.$q$, $q$Over time Workable has expanded beyond pure recruiting into a lightweight HR information system, adding onboarding, time-off tracking, time tracking, e-signatures, and payroll preparation, positioning the platform as a combined hire-to-onboard tool for small and mid-sized businesses.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('63552ca4-8785-47c6-9aaf-f0643adf97b5', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Multi-board job posting and a searchable candidate sourcing database help teams find and attract applicants without manually posting to each job board individually.$q$, $q$An AI recruiting agent can auto-source and pre-screen candidates, while optional add-ons cover video interviewing, skills assessments, SMS texting, and structured employee referrals.$q$, $q$The HR side of the platform includes employee onboarding workflows, time-off and time tracking, e-signatures for offer letters and HR documents, an employee directory and org chart, and payroll preparation with third-party payroll integrations.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('63552ca4-8785-47c6-9aaf-f0643adf97b5', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Workable sells three plan tiers scaled for companies ranging from around 1 to 20 employees up through enterprises of 1,000-plus staff. Standard costs 299 dollars per month (3,588 dollars annually with a 20 percent discount), with video interviews, assessments, and texting sold as separate add-ons.$q$, $q$Premier costs 599 dollars per month (7,188 dollars annually) and bundles in texting, video interviews, assessments, referrals, and performance and engagement tools that are optional extras on Standard.$q$, $q$Enterprise costs 719 dollars per month (8,628 dollars annually) with the same feature set as Premier, aimed at larger organizations needing single sign-on and priority support. All tiers include free AI credits for the Workable Agent, with additional credits purchasable in bulk.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b7dbfbf6-f142-4013-ba06-5ff42e255059', $q$Recipe-Based Workflow Builder$q$, $q$A no-code or low-code way to define triggers and actions across connected applications.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b7dbfbf6-f142-4013-ba06-5ff42e255059', $q$1,200+ Pre-Built Connectors$q$, $q$Ready-made integrations spanning ERP, CRM, HR, database, and cloud service platforms.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b7dbfbf6-f142-4013-ba06-5ff42e255059', $q$Agent Studio$q$, $q$A visual, low-code environment for designing, testing, and deploying enterprise-grade AI agents.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b7dbfbf6-f142-4013-ba06-5ff42e255059', $q$Workato Genies$q$, $q$Prebuilt AI agents scoped to specific business functions such as sales, IT, HR, and customer experience.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b7dbfbf6-f142-4013-ba06-5ff42e255059', $q$Enterprise MCP Support$q$, $q$Connects Workato automations to large language model tool-calling standards for agentic AI workflows.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b7dbfbf6-f142-4013-ba06-5ff42e255059', $q$Community Recipe Library$q$, $q$Over 225,000 pre-built recipe templates covering common workflows like quote-to-cash and employee onboarding.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b7dbfbf6-f142-4013-ba06-5ff42e255059', $q$Enterprise Governance$q$, $q$Controls for security, compliance, and reliability suited to large-scale enterprise automation deployments.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b7dbfbf6-f142-4013-ba06-5ff42e255059', $q$Embedded Integration (Workato Embed)$q$, $q$Lets software vendors embed Workato's integration capabilities directly into their own products.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b7dbfbf6-f142-4013-ba06-5ff42e255059', $q$Extensive connector library covers most common enterprise applications$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b7dbfbf6-f142-4013-ba06-5ff42e255059', $q$Combines traditional integration automation with newer AI agent orchestration in one platform$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b7dbfbf6-f142-4013-ba06-5ff42e255059', $q$Large community recipe library speeds up common workflow setup$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b7dbfbf6-f142-4013-ba06-5ff42e255059', $q$Built for enterprise-grade reliability, governance, and transaction volume$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b7dbfbf6-f142-4013-ba06-5ff42e255059', $q$Actively investing in agentic AI features like Agent Studio and Genies$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b7dbfbf6-f142-4013-ba06-5ff42e255059', $q$No published self-serve pricing, requiring a sales process to get a quote$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b7dbfbf6-f142-4013-ba06-5ff42e255059', $q$Higher cost and complexity than lightweight tools like Zapier, aimed more at mid-market and enterprise buyers$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b7dbfbf6-f142-4013-ba06-5ff42e255059', $q$No public free tier for individuals or very small teams to try the platform$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b7dbfbf6-f142-4013-ba06-5ff42e255059', $q$Learning curve for building complex recipes and governing them at enterprise scale$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b7dbfbf6-f142-4013-ba06-5ff42e255059', $q$What is Workato used for?$q$, $q$Workato is used to integrate business applications and automate cross-application workflows through no-code recipes, and increasingly to build and govern AI agents.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b7dbfbf6-f142-4013-ba06-5ff42e255059', $q$How much does Workato cost?$q$, $q$Workato does not publish pricing; it requires a custom quote from sales, with third-party estimates suggesting enterprise contracts typically start around 10,000 dollars per year.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b7dbfbf6-f142-4013-ba06-5ff42e255059', $q$Who founded Workato?$q$, $q$Workato was founded in December 2013 by Vijay Tella, Gautham Viswanathan, Harish Shetty, and Dimitris Kogias, former colleagues from TIBCO Software.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b7dbfbf6-f142-4013-ba06-5ff42e255059', $q$What is a recipe in Workato?$q$, $q$A recipe is Workato's core workflow unit, defining a trigger event in one application and one or more resulting actions in connected applications.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b7dbfbf6-f142-4013-ba06-5ff42e255059', $q$Does Workato support AI agents?$q$, $q$Yes, Workato offers Agent Studio for building custom AI agents and Workato Genies, which are prebuilt agents scoped to specific business functions.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b7dbfbf6-f142-4013-ba06-5ff42e255059', $q$How many connectors does Workato offer?$q$, $q$Workato offers more than 1,200 pre-built connectors spanning ERP, CRM, HR, database, and cloud service platforms.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b7dbfbf6-f142-4013-ba06-5ff42e255059', $q$Is Workato good for small businesses?$q$, $q$Workato is primarily built for mid-market and enterprise organizations; smaller teams may find lighter tools like Zapier more cost-effective.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b7dbfbf6-f142-4013-ba06-5ff42e255059', $q$Where is Workato headquartered?$q$, $q$Workato is headquartered in Mountain View, California.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b7dbfbf6-f142-4013-ba06-5ff42e255059', $q$Cross-application workflow automation$q$, $q$Enterprises connect ERP, CRM, and HR systems to automate processes like quote-to-cash and employee onboarding.$q$, $q$Enterprise IT and operations teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b7dbfbf6-f142-4013-ba06-5ff42e255059', $q$Embedded integration for SaaS vendors$q$, $q$Software companies use Workato Embed to offer native integration capabilities inside their own products.$q$, $q$SaaS product teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b7dbfbf6-f142-4013-ba06-5ff42e255059', $q$AI agent orchestration$q$, $q$Organizations use Agent Studio and Genies to deploy AI agents that coordinate automated processes across business systems.$q$, $q$Enterprise automation and AI teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('b7dbfbf6-f142-4013-ba06-5ff42e255059', $q$Enterprise$q$, $q$Custom$q$, $q$annual contract$q$, NULL, $q$["1,200+ connectors","Unlimited recipe library access","Agent Studio and Workato Genies","Enterprise governance and support"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b7dbfbf6-f142-4013-ba06-5ff42e255059', $q$overview$q$, $q$What Is Workato$q$, 2, ARRAY[$q$Workato is an enterprise integration platform as a service, or iPaaS, founded in December 2013 in Mountain View, California by Vijay Tella, Gautham Viswanathan, Harish Shetty, and Dimitris Kogias, who had previously worked together building the BusinessWorks integration platform at TIBCO Software.$q$, $q$The platform's core concept is the recipe, a no-code or low-code workflow made of a trigger in one application and one or more resulting actions in other connected applications. Recipes are reusable and shareable across an organization, and Workato maintains a community library of over 225,000 pre-built recipe templates.$q$, $q$Workato has expanded from pure application integration into AI agent orchestration, offering tools to design, deploy, and govern AI agents that coordinate with business systems and human workflows alongside its traditional automation recipes.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b7dbfbf6-f142-4013-ba06-5ff42e255059', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Over 1,200 pre-built connectors span ERP systems, CRMs, HR platforms, databases, and cloud services, letting enterprises automate cross-application workflows without custom integration code.$q$, $q$Agent Studio provides a visual, low-code environment for designing, testing, and deploying enterprise-grade AI agents, while Workato Genies are prebuilt AI agents scoped to functions like sales, IT, HR, marketing, and customer experience.$q$, $q$Enterprise MCP support connects Workato automations to large language model tool-calling standards, and the platform processes billions of transactions monthly for more than 17,000 customers with governance controls suited to enterprise IT requirements.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b7dbfbf6-f142-4013-ba06-5ff42e255059', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Workato does not publish self-serve pricing or offer a public free tier; access requires contacting sales for a custom quote based on the organization's needs.$q$, $q$Pricing typically scales with the number of recipes, connected applications, and transaction volume rather than a flat per-seat rate, reflecting its focus on mid-market and enterprise customers.$q$, $q$Third-party estimates suggest typical enterprise contracts start in the range of 10,000 dollars per year, though actual pricing varies significantly based on scale and the specific modules an organization licenses.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('b7dbfbf6-f142-4013-ba06-5ff42e255059', '87a92d11-ee13-4164-9910-61410254388a') ON CONFLICT DO NOTHING;
