INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8b71f7fc-c26a-419f-a1fe-0de98471da7f', $q$Workday Adaptive Planning$q$, $q$Financial and workforce planning and forecasting tools for budgeting and scenario modeling.$q$, 2);
