INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8b71f7fc-c26a-419f-a1fe-0de98471da7f', $q$Unified Cloud Architecture$q$, $q$A single multi-tenant codebase and data model shared across all customers, with frequent automatic updates.$q$, 7);
