INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8b71f7fc-c26a-419f-a1fe-0de98471da7f', $q$Frequent updates delivered automatically as part of the multi-tenant cloud architecture$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8b71f7fc-c26a-419f-a1fe-0de98471da7f', $q$Broad module ecosystem covering HCM, finance, planning, procurement, and analytics$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8b71f7fc-c26a-419f-a1fe-0de98471da7f', $q$Strong track record with large enterprises across regulated industries like healthcare and higher education$q$, 3);
