INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8b71f7fc-c26a-419f-a1fe-0de98471da7f', $q$Implementation can be lengthy and costly, often requiring systems integrator involvement$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8b71f7fc-c26a-419f-a1fe-0de98471da7f', $q$Primarily built for large and mid-market enterprises, less suited to very small businesses$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8b71f7fc-c26a-419f-a1fe-0de98471da7f', $q$Customization within the multi-tenant architecture is more constrained than fully bespoke on-premises systems$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8b71f7fc-c26a-419f-a1fe-0de98471da7f', $q$What is Workday used for?$q$, $q$Workday is used by organizations for human capital management, financial management, payroll, and workforce and financial planning through a unified cloud platform.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8b71f7fc-c26a-419f-a1fe-0de98471da7f', $q$How much does Workday cost?$q$, $q$Workday does not publish pricing; costs are custom-quoted per organization, with third-party estimates placing core HCM subscriptions starting around 100 dollars per user per year before add-ons.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8b71f7fc-c26a-419f-a1fe-0de98471da7f', $q$Who founded Workday?$q$, $q$Workday was founded in March 2005 by David Duffield, former CEO of PeopleSoft, and Aneel Bhusri, PeopleSoft's former chief strategist.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8b71f7fc-c26a-419f-a1fe-0de98471da7f', $q$Where is Workday headquartered?$q$, $q$Workday is headquartered in Pleasanton, California.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8b71f7fc-c26a-419f-a1fe-0de98471da7f', $q$Is Workday an ERP system?$q$, $q$Workday functions as a cloud ERP covering human capital management and financial management, and is often categorized alongside traditional ERP vendors like SAP and Oracle.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8b71f7fc-c26a-419f-a1fe-0de98471da7f', $q$Does Workday include AI features?$q$, $q$Yes, Workday has introduced Illuminate, a suite of embedded AI and agent capabilities across its HCM, finance, and planning applications.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8b71f7fc-c26a-419f-a1fe-0de98471da7f', $q$What size companies use Workday?$q$, $q$Workday primarily serves large enterprises and increasingly mid-market organizations across industries such as healthcare, higher education, financial services, and technology.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8b71f7fc-c26a-419f-a1fe-0de98471da7f', $q$Is Workday publicly traded?$q$, $q$Yes, Workday is publicly traded on the Nasdaq stock exchange under the ticker symbol WDAY.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('8b71f7fc-c26a-419f-a1fe-0de98471da7f', $q$Enterprise HR and payroll management$q$, $q$Large organizations use Workday HCM and Payroll to manage employee records, compensation, and payroll in one system.$q$, $q$Enterprise HR departments$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('8b71f7fc-c26a-419f-a1fe-0de98471da7f', $q$Unified financial and workforce planning$q$, $q$Finance teams use Workday Financial Management alongside Adaptive Planning to align budgeting with workforce data.$q$, $q$Enterprise finance and FP&A teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('8b71f7fc-c26a-419f-a1fe-0de98471da7f', $q$Higher education and healthcare administration$q$, $q$Universities and healthcare systems use Workday to manage complex HR, payroll, and financial operations across large, regulated organizations.$q$, $q$Higher education and healthcare institutions$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('8b71f7fc-c26a-419f-a1fe-0de98471da7f', $q$Human Capital Management$q$, $q$Custom (est. from ~$100/user/year)$q$, $q$annual subscription$q$, NULL, $q$["Core HR and talent management","Compensation management","Workforce planning basics"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('8b71f7fc-c26a-419f-a1fe-0de98471da7f', $q$Financial Management$q$, $q$Custom$q$, $q$annual subscription$q$, NULL, $q$["Accounting and reporting","Procurement","Integration with HCM data"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('8b71f7fc-c26a-419f-a1fe-0de98471da7f', $q$Enterprise Bundle$q$, $q$Custom$q$, $q$annual subscription$q$, NULL, $q$["HCM, Financial Management, Payroll, Adaptive Planning","Prism Analytics","Workday Illuminate AI capabilities"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('8b71f7fc-c26a-419f-a1fe-0de98471da7f', $q$overview$q$, $q$What Is Workday$q$, 2, ARRAY[$q$Workday is a cloud-based enterprise software company founded in March 2005 by David Duffield, former CEO of PeopleSoft, and Aneel Bhusri, PeopleSoft's former chief strategist, following Oracle's acquisition of PeopleSoft. The company launched its first product in 2006 and is headquartered in Pleasanton, California.$q$, $q$The platform's flagship products are Human Capital Management and Financial Management, delivered as unified cloud applications rather than the on-premises, modular systems typical of older ERP vendors. Workday extends this with Adaptive Planning for financial and workforce planning, Payroll, Strategic Sourcing for procurement, Prism Analytics, and Illuminate, its embedded AI and agent capability layer.$q$, $q$Workday primarily serves large enterprises and increasingly mid-market organizations across healthcare, higher education, financial services, technology, and government, competing with SAP SuccessFactors and Oracle Cloud HCM among others.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('8b71f7fc-c26a-419f-a1fe-0de98471da7f', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Workday HCM covers core HR, talent management, compensation, and workforce planning within a single unified data model shared across all Workday applications.$q$, $q$Workday Financial Management provides accounting, procurement, and financial reporting built on the same cloud architecture, allowing HR and finance data to be reported on together without separate integration projects.$q$, $q$Adjacent modules such as Adaptive Planning for budgeting and forecasting, Prism Analytics for broader data analysis, and the Illuminate AI layer extend the core platform with planning and AI-assisted decision-making capabilities.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('8b71f7fc-c26a-419f-a1fe-0de98471da7f', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Workday sells its products entirely on a subscription basis and does not publish self-serve pricing. Contracts are individually negotiated based on the modules licensed, the number of employees or users covered, and the scope of implementation.$q$, $q$Third-party estimates place core HCM subscription costs starting in the range of roughly 100 dollars per user per year, with total spend rising significantly once financial management, payroll, planning, or analytics modules are added.$q$, $q$Large enterprise implementations often involve substantial additional costs for systems integrator services, which can push total first-year investment into the millions of dollars for the largest organizations.$q$]::text[], 2);
